  imports: [UIAutocomplete, JsonPipe],
  template: `
    <ui-autocomplete
      [datasource]="ds"
      [(value)]="selected"
      placeholder="Search fruits…"
      ariaLabel="Fruit search"
    />
    <pre class="story-output">Selected: {{ selected() | json }}</pre>
  `,
  styles: [
    `
      :host {
        display: block;
        max-width: 400px;
      }
      .story-output {
        margin-top: 1rem;
        font-size: 0.8125rem;
        padding: 0.75rem;
        background: var(--tv-surface-2, #fbfbfc);
        color: var(--tv-text, #1d232b);
        border: 1px solid var(--tv-border, #d7dce2);
        border-radius: 4px;
        font-family: var(--tv-font, monospace);
        overflow-x: auto;
      }
    `,
  ],
})
class BasicDemo {
  readonly ds = new FruitDatasource();
  readonly selected = signal<readonly string[]>([]);
}

