/**
 * Custom template demo with rich Contact objects.
 */
@Component({
  selector: "ui-ac-template-demo",
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [UIAutocomplete, JsonPipe],
  template: `
    <ui-autocomplete
      [datasource]="ds"
      [(value)]="selected"
      [multiple]="true"
      [displayWith]="displayContact"
      [trackBy]="trackByEmail"
      placeholder="Search contacts…"
      ariaLabel="Contact search"
    >
      <ng-template let-item>
        <div class="contact-item">
          <strong>{{ item.name }}</strong>
          <small>{{ item.email }} · {{ item.department }}</small>
        </div>
      </ng-template>
    </ui-autocomplete>
    <pre class="story-output">Selected: {{ selected() | json }}</pre>
  `,
  styles: [
    `
      :host {
        display: block;
        max-width: 480px;
      }
      .contact-item {
        display: flex;
        flex-direction: column;
        gap: 2px;
        padding: 2px 0;
      }
      .contact-item strong {
        font-weight: 600;
      }
      .contact-item small {
        font-size: 0.75rem;
        opacity: 0.7;
      }
      .story-output {
        margin-top: 1rem;
        font-size: 0.8125rem;
        padding: 0.75rem;
        background: var(--tv-surface-2, #fbfbfc);
        color: var(--tv-text, #1d232b);
        border: 1px solid var(--tv-border, #d7dce2);
        border-radius: 4px;
        font-family: var(--tv-font, monospace);
        overflow-x: auto;
      }
    `,
  ],
})
class TemplateDemo {
  readonly ds = new ContactDatasource();
  readonly selected = signal<readonly Contact[]>([]);
  readonly displayContact = (c: Contact) => c.name;
  readonly trackByEmail = (c: Contact) => c.email;
}

/**
 * Disabled state demo.
 */
