// ── Story meta ─────────────────────────────────────────────────────

const meta: Meta = {
  title: "@Theredhead/UI Kit/Autocomplete",
  tags: ["autodocs"],
  decorators: [
    moduleMetadata({
      imports: [
        UIAutocomplete,
        BasicDemo,
        MultiDemo,
        TemplateDemo,
        DisabledDemo,
      ],
    }),
  ],
};

export default meta;
type Story = StoryObj;

// ── Stories ─────────────────────────────────────────────────────────

/** Basic single-select autocomplete with a fruit list. */
export const Basic: Story = {
  render: () => ({
    template: `<ui-ac-basic-demo />`,
  }),
};

/**
 * Multi-select mode — selected items appear as removable chips above the
 * input. Already-selected items are excluded from suggestions.
 */
export const MultipleSelection: Story = {
  render: () => ({
    template: `<ui-ac-multi-demo />`,
  }),
};

/**
 * Custom item template with rich Contact objects.
 * Uses `displayWith` for chip labels and `trackBy` for identity.
 */
export const CustomTemplate: Story = {
  render: () => ({
    template: `<ui-ac-template-demo />`,
  }),
};

/** Disabled state — the input cannot be focused or typed into. */
export const Disabled: Story = {
  render: () => ({
    template: `<ui-ac-disabled-demo />`,
  }),
};

import { ChangeDetectionStrategy, Component, signal } from "@angular/core";
import { JsonPipe } from "@angular/common";

import type { Meta, StoryObj } from "@storybook/angular";
import { moduleMetadata } from "@storybook/angular";

import { UIFilter } from "./filter.component";
import type { FilterDescriptor, FilterFieldDefinition } from "./filter.types";

// ---------------------------------------------------------------------------
// Demo wrapper — shows the filter builder + live JSON output
// ---------------------------------------------------------------------------

interface DemoRow {
  name: string;
  age: number;
  email: string;
  salary: number;
  hireDate: string;
}

const DEMO_FIELDS: FilterFieldDefinition<DemoRow>[] = [
  { key: "name", label: "Name", type: "string" },
  { key: "email", label: "Email", type: "string" },
  { key: "age", label: "Age", type: "number" },
  { key: "salary", label: "Salary", type: "number" },
  { key: "hireDate", label: "Hire Date", type: "date" },
];

@Component({
  selector: "ui-filter-story-demo",
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [UIFilter, JsonPipe],
  template: `
    <ui-filter
      [fields]="fields"
      [allowJunction]="allowJunction()"
      [(value)]="descriptor"
    />
    <pre
      style="margin-top:1rem;font-size:0.8125rem;background:var(--tv-surface-2,#fbfbfc);color:var(--tv-text,#1d232b);border:1px solid var(--tv-border,#d7dce2);padding:0.75rem;border-radius:0;overflow-x:auto;font-family:var(--tv-font,monospace);"
      >{{ descriptor() | json }}</pre
    >
  `,
