      style="display:flex;justify-content:flex-end;gap:0.5rem;margin:0 0 0.75rem;"
    >
      <button (click)="toggle()">
        {{ highlighted() ? "Remove highlight" : "Highlight route" }}
      </button>
      <ui-theme-toggle
        variant="button"
        [showTooltip]="true"
        ariaLabel="Toggle theme"
      />
    </div>
    <ui-map-view
      [center]="center"
      [zoom]="6"
      [markers]="markers"
      [polylines]="polylines()"
      [polygons]="polygons()"
