import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from "@angular/core";

import { UIButton } from "../button/button.component";
import { UIInput } from "../input/input.component";
import { UISelect } from "../select/select.component";
import type { SelectOption } from "../select/select.component";
import {
  DATE_UNIT_OPTIONS,
  type FilterFieldDefinition,
  type FilterOperator,
  type FilterRule,
  isNoValueOperator,
  operatorsForType,
} from "./filter.types";

/**
 * A single row inside a {@link UIFilter} predicate builder.
 *
 * Renders: **field dropdown → operator dropdown → value input(s) → remove button**.
 *
 * @internal — consumed by `UIFilter`; not intended for direct use.
 */
@Component({
  selector: "ui-filter-row",
  standalone: true,
  imports: [UISelect, UIInput, UIButton],
  templateUrl: "./filter-row.component.html",
  styleUrl: "./filter-row.component.scss",
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: "ui-filter-row" },
})
export class UIFilterRow {
  // ── Inputs ──────────────────────────────────────────────────────────
  /** Available filterable fields. */
  readonly fields = input.required<FilterFieldDefinition[]>();

  /** The current rule state (immutable — changes are emitted via {@link ruleChange}). */
  readonly rule = input.required<FilterRule>();

  // ── Outputs ─────────────────────────────────────────────────────────
  /** Emits the updated rule whenever the user changes any part of it. */
  readonly ruleChange = output<FilterRule>();

  /** Emits when the user clicks the remove button. */
  readonly remove = output<void>();

  // ── Derived state ───────────────────────────────────────────────────

  /** SelectOption list built from the field definitions. */
  protected readonly fieldOptions = computed<SelectOption[]>(() =>
    this.fields().map((f) => ({ value: f.key, label: f.label })),
  );

  /** The currently selected field definition (if any). */
  protected readonly selectedField = computed(() =>
    this.fields().find((f) => f.key === this.rule().field),
  );

  /** Operator options matching the selected field's type. */
  protected readonly operatorOptions = computed<SelectOption[]>(() => {
    const field = this.selectedField();
    return field ? operatorsForType(field.type) : [];
  });

  /** The native `<input>` type matching the selected field's type. */
  protected readonly inputType = computed<"text" | "number" | "date">(() => {
    const t = this.selectedField()?.type;
    if (t === "number") return "number";
    if (t === "date") return "date";
    return "text";
  });

  /** Whether to hide the value input (for isEmpty / isNotEmpty). */
  protected readonly hideValue = computed(() =>
    isNoValueOperator(this.rule().operator),
  );

  /** Whether the operator requires a second value (between). */
  protected readonly isBetween = computed(
    () => this.rule().operator === "between",
  );

  /** Whether the operator is the relative-date "in the last" variant. */
  protected readonly isInTheLast = computed(
    () => this.rule().operator === "inTheLast",
  );

  /** Options for the date-unit dropdown. */
  protected readonly dateUnitOptions = DATE_UNIT_OPTIONS;

  // ── Event handlers ──────────────────────────────────────────────────

  protected onFieldChange(key: string): void {
    const field = this.fields().find((f) => f.key === key);
    const ops = field ? operatorsForType(field.type) : [];
    this.ruleChange.emit({
      ...this.rule(),
      field: key,
      operator: (ops[0]?.value ?? "equals") as FilterOperator,
      value: "",
      valueTo: undefined,
      unit: undefined,
    });
  }

  protected onOperatorChange(op: string): void {
    const patch: Partial<FilterRule> = { operator: op as FilterOperator };
    // Reset secondary fields when switching away from specialised operators
    if (op !== "between") patch.valueTo = undefined;
    if (op !== "inTheLast") patch.unit = undefined;
    if (isNoValueOperator(op)) {
      patch.value = "";
      patch.valueTo = undefined;
    }
    this.ruleChange.emit({ ...this.rule(), ...patch });
  }

  protected onValueChange(value: string): void {
    this.ruleChange.emit({ ...this.rule(), value });
  }

  protected onValueToChange(valueTo: string): void {
    this.ruleChange.emit({ ...this.rule(), valueTo });
  }

  protected onUnitChange(unit: string): void {
    this.ruleChange.emit({
      ...this.rule(),
      unit: unit as FilterRule["unit"],
    });
  }
}

import { ChangeDetectionStrategy, Component, signal } from "@angular/core";
import { JsonPipe } from "@angular/common";

import type { Meta, StoryObj } from "@storybook/angular";
import { moduleMetadata } from "@storybook/angular";

import { UIFilter } from "./filter.component";
import type { FilterDescriptor, FilterFieldDefinition } from "./filter.types";

// ---------------------------------------------------------------------------
// Demo wrapper — shows the filter builder + live JSON output
// ---------------------------------------------------------------------------

interface DemoRow {
  name: string;
  age: number;
  email: string;
  salary: number;
  hireDate: string;
}

const DEMO_FIELDS: FilterFieldDefinition<DemoRow>[] = [
  { key: "name", label: "Name", type: "string" },
  { key: "email", label: "Email", type: "string" },
  { key: "age", label: "Age", type: "number" },
  { key: "salary", label: "Salary", type: "number" },
  { key: "hireDate", label: "Hire Date", type: "date" },
];

@Component({
  selector: "ui-filter-story-demo",
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [UIFilter, JsonPipe],
  template: `
    <ui-filter
      [fields]="fields"
      [allowJunction]="allowJunction()"
      [(value)]="descriptor"
    />
    <pre
      style="margin-top:1rem;font-size:0.8125rem;background:var(--tv-surface-2,#fbfbfc);color:var(--tv-text,#1d232b);border:1px solid var(--tv-border,#d7dce2);padding:0.75rem;border-radius:0;overflow-x:auto;font-family:var(--tv-font,monospace);"
      >{{ descriptor() | json }}</pre
    >
  `,
})
class UIFilterStoryDemo {
  readonly fields = DEMO_FIELDS;
  readonly allowJunction = signal(false);
  readonly descriptor = signal<FilterDescriptor<DemoRow>>({
    junction: "and",
    rules: [],
  });
}

// ---------------------------------------------------------------------------
// Story meta
// ---------------------------------------------------------------------------

const meta: Meta<UIFilterStoryDemo> = {
  title: "@Theredhead/UI Kit/Filter",
  component: UIFilterStoryDemo,
  tags: ["autodocs"],
  decorators: [
    moduleMetadata({
      imports: [UIFilter],
    }),
  ],
};

export default meta;
type Story = StoryObj<UIFilterStoryDemo>;

/** Basic AND-only filter builder. */
export const Default: Story = {};

/** With junction toggle (AND / OR). */
export const WithJunction: Story = {
  render: () => ({
    template: `
      <ui-filter
        [fields]="fields"
        [allowJunction]="true"
        [(value)]="descriptor"
      />
      <pre style="margin-top:1rem;font-size:0.8125rem;background:var(--tv-surface-2,#fbfbfc);color:var(--tv-text,#1d232b);border:1px solid var(--tv-border,#d7dce2);padding:0.75rem;overflow-x:auto;font-family:var(--tv-font,monospace);">{{ descriptor | json }}</pre>
    `,
    props: {
      fields: DEMO_FIELDS,
      descriptor: { junction: "and", rules: [] } as FilterDescriptor<DemoRow>,
    },
  }),
};

/** Pre-populated with a few rules. */
export const Prepopulated: Story = {
  render: () => ({
    template: `
      <ui-filter
        [fields]="fields"
        [allowJunction]="true"
        [(value)]="descriptor"
      />
      <pre style="margin-top:1rem;font-size:0.8125rem;background:var(--tv-surface-2,#fbfbfc);color:var(--tv-text,#1d232b);border:1px solid var(--tv-border,#d7dce2);padding:0.75rem;overflow-x:auto;font-family:var(--tv-font,monospace);">{{ descriptor | json }}</pre>
    `,
    props: {
      fields: DEMO_FIELDS,
      descriptor: {
        junction: "and",
        rules: [
          { id: 1, field: "name", operator: "contains", value: "John" },
          { id: 2, field: "age", operator: "greaterThan", value: "25" },
          {
            id: 3,
            field: "hireDate",
            operator: "inTheLast",
            value: "6",
            unit: "months",
          },
        ],
      } as FilterDescriptor<DemoRow>,
    },
  }),
};

import {
  ChangeDetectionStrategy,
  Component,
  input,
  model,
} from "@angular/core";

/**
 * Thin wrapper around a native `<input>` element.
 *
 * Supports two-way binding via {@link value} (`[(value)]`).
 *
 * @example
 * ```html
 * <ui-input type="number" [(value)]="amount" placeholder="Enter amount" />
 * ```
 */
@Component({
  selector: "ui-input",
  standalone: true,
  templateUrl: "./input.component.html",
  styleUrl: "./input.component.scss",
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: "ui-input" },
})
export class UIInput {
  /** Native input type. */
  readonly type = input<"text" | "number" | "date">("text");

  /** Current value (two-way bindable). */
  readonly value = model("");

  /** Placeholder text. */
  readonly placeholder = input("");

  /** Whether the control is disabled. */
  readonly disabled = input(false);

  /**
   * Accessible label forwarded to the native `<input>` as `aria-label`.
   *
   * Required when no visible `<label>` is associated with the control.
   */
  readonly ariaLabel = input<string | undefined>(undefined);

  /** @internal */
  protected onInput(event: Event): void {
    this.value.set((event.target as HTMLInputElement).value);
  }
}

